import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { alumniApi } from '../api/alumniApi';
import { toast } from 'react-toastify';
import { 
  Search, 
  MapPin, 
  Calendar, 
  Briefcase, 
  Building,
  GraduationCap,
  Mail,
  Phone,
  Plus,
  Edit,
  Trash2
} from 'lucide-react';
import Card from '../components/Card';
import '../styles/AlumniDirectory.css';

const AlumniDirectory = () => {
  const [alumni, setAlumni] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({
    graduationYear: '',
    fieldOfStudy: '',
    location: ''
  });
  
  const { isAdmin } = useAuth();

  useEffect(() => {
    fetchAlumni();
  }, []);

  const fetchAlumni = async () => {
    try {
      setLoading(true);
      const response = await alumniApi.getAll();
      setAlumni(response.data);
    } catch {
      toast.error('Failed to fetch alumni data');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async () => {
    try {
      setLoading(true);
      const response = await alumniApi.search(searchTerm);
      setAlumni(response.data);
    } catch {
      toast.error('Search failed');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this alumni record?')) {
      try {
        await alumniApi.delete(id);
        toast.success('Alumni record deleted successfully');
        fetchAlumni();
      } catch {
        toast.error('Failed to delete alumni record');
      }
    }
  };

  const filteredAlumni = alumni.filter(alumnus => {
    const matchesSearch = !searchTerm || 
      alumnus.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      alumnus.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      alumnus.fieldOfStudy?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      alumnus.currentPosition?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesFilters = 
      (!filters.graduationYear || alumnus.graduationYear === filters.graduationYear) &&
      (!filters.fieldOfStudy || alumnus.fieldOfStudy?.toLowerCase().includes(filters.fieldOfStudy.toLowerCase())) &&
      (!filters.location || alumnus.location?.toLowerCase().includes(filters.location.toLowerCase()));

    return matchesSearch && matchesFilters;
  });

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="spinner"></div>
    </div>
  );

  return (
    <div className="alumni-directory">
      <div className="container">
        {/* Header */}
        <div className="header mb-8">
          <h1>Alumni Directory</h1>
          <p>Connect with fellow alumni and explore networking opportunities</p>
        </div>

        {/* Search & Filters */}
        <Card className="filters-card mb-8">
          <div className="filters-grid mb-4">
            <div className="relative">
              <Search className="input-icon" />
              <input
                type="text"
                placeholder="Search alumni..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="form-input pl-10"
              />
            </div>
            <select
              value={filters.graduationYear}
              onChange={(e) => setFilters({...filters, graduationYear: e.target.value})}
              className="form-select"
            >
              <option value="">All Graduation Years</option>
              {Array.from({length: 20}, (_, i) => 2024 - i).map(year => (
                <option key={year} value={year}>{year}</option>
              ))}
            </select>
            <input
              type="text"
              placeholder="Field of Study"
              value={filters.fieldOfStudy}
              onChange={(e) => setFilters({...filters, fieldOfStudy: e.target.value})}
              className="form-input"
            />
            <input
              type="text"
              placeholder="Location"
              value={filters.location}
              onChange={(e) => setFilters({...filters, location: e.target.value})}
              className="form-input"
            />
          </div>

          <div className="flex justify-between items-center">
            <button onClick={handleSearch} className="btn btn-primary">
              <Search className="h-4 w-4 mr-2" />
              Search
            </button>
            {isAdmin && (
              <button className="btn btn-primary">
                <Plus className="h-4 w-4 mr-2" />
                Add Alumni
              </button>
            )}
          </div>
        </Card>

        {/* Alumni Grid */}
        <div className="alumni-grid">
          {filteredAlumni.map((alumnus) => (
            <Card key={alumnus._id} className="alumni-card">
              <div className="card-header">
                <div className="alumnus-info">
                  <div className="avatar">
                    <GraduationCap className="h-6 w-6 text-blue-600" />
                  </div>
                  <div>
                    <h3>{alumnus.name}</h3>
                    <p>{alumnus.email}</p>
                  </div>
                </div>
                {isAdmin && (
                  <div className="admin-actions">
                    <button onClick={() => setEditingAlumni(alumnus)}>
                      <Edit className="h-4 w-4" />
                    </button>
                    <button onClick={() => handleDelete(alumnus._id)}>
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                )}
              </div>

              <div className="alumnus-details">
                {alumnus.graduationYear && (
                  <div className="detail-item">
                    <Calendar className="h-4 w-4 mr-2" />
                    Class of {alumnus.graduationYear}
                  </div>
                )}
                {alumnus.fieldOfStudy && (
                  <div className="detail-item">
                    <GraduationCap className="h-4 w-4 mr-2" />
                    {alumnus.fieldOfStudy}
                  </div>
                )}
                {alumnus.currentPosition && (
                  <div className="detail-item">
                    <Briefcase className="h-4 w-4 mr-2" />
                    {alumnus.currentPosition}
                  </div>
                )}
                {alumnus.company && (
                  <div className="detail-item">
                    <Building className="h-4 w-4 mr-2" />
                    {alumnus.company}
                  </div>
                )}
                {alumnus.location && (
                  <div className="detail-item">
                    <MapPin className="h-4 w-4 mr-2" />
                    {alumnus.location}
                  </div>
                )}
              </div>

              <div className="card-footer">
                <button className="btn btn-outline flex-1">
                  <Mail className="h-4 w-4 mr-1" /> Contact
                </button>
                <button className="btn btn-primary flex-1">
                  <Phone className="h-4 w-4 mr-1" /> Connect
                </button>
              </div>
            </Card>
          ))}
        </div>

        {filteredAlumni.length === 0 && (
          <div className="empty-state">
            <GraduationCap className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <h3>No alumni found</h3>
            <p>Try adjusting your search criteria</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AlumniDirectory;
